command:
ssh -i /home/jose/.ssh/n8n_bridge -o StrictHostKeyChecking=no jose@192.168.0.202 "cat > /tmp/check_acp.sh << 'SHEOF'
echo === ACP ADAPTER ===
ls /home/jose/.hermes/hermes-agent/acp_adapter/
echo === ACP REGISTRY ===
ls /home/jose/.hermes/hermes-agent/acp_registry/
cat /home/jose/.hermes/hermes-agent/acp_registry/*.json 2>/dev/null | head -30
echo === GATEWAY CONFIG ===
grep -E 'port|bind|http|api|mcp|acp' /home/jose/.hermes/config.yaml | head -20
echo === HERMES CLI HELP ===
/home/jose/.hermes/hermes-agent/venv/bin/hermes gateway --help 2>&1 | head -20
SHEOF
bash /tmp/check_acp.sh"
